import numpy as np

def sensitivity_analysis(N):
    """Analyze sensitivity to iteration count."""
    theta = np.arcsin(1/np.sqrt(N))
    r_opt = int(round(np.pi / (4*theta) - 0.5))

    def prob_at(r):
        return np.sin((2*r + 1) * theta)**2

    optimal_prob = prob_at(r_opt)

    # Calculate deviations
    deviations = {}
    for delta in range(-5, 6):
        r = r_opt + delta
        if r >= 0:
            deviations[delta] = prob_at(r)

    # Find safe range (prob > 0.9)
    min_safe, max_safe = r_opt, r_opt
    for r in range(r_opt, -1, -1):
        if prob_at(r) >= 0.9:
            min_safe = r
        else:
            break
    for r in range(r_opt, r_opt + 20):
        if prob_at(r) >= 0.9:
            max_safe = r
        else:
            break

    return {
        'optimal_r': r_opt,
        'optimal_prob': optimal_prob,
        'deviations': deviations,
        'safe_range': (min_safe, max_safe)
    }

def print_sensitivity_report(N):
    """Print a formatted sensitivity report."""
    results = sensitivity_analysis(N)

    print(f"Sensitivity Analysis for N={N}")
    print("=" * 45)
    print(f"Optimal iterations: {results['optimal_r']}")
    print(f"Optimal probability: {results['optimal_prob']:.6f}")
    print(f"Safe range (>90%): {results['safe_range'][0]} to {results['safe_range'][1]}")
    print(f"Safe window size: {results['safe_range'][1] - results['safe_range'][0] + 1} iterations")

    print("\nDeviation from optimal:")
    print(f"{'Delta':>6} {'r':>4} {'Prob':>10} {'Loss':>10}")
    print("-" * 35)

    opt_prob = results['optimal_prob']
    for delta, prob in sorted(results['deviations'].items()):
        r = results['optimal_r'] + delta
        loss = (opt_prob - prob) * 100
        print(f"{delta:>+6} {r:>4} {prob:>10.6f} {loss:>+10.2f}%")

for N in [64, 256, 1024]:
    print_sensitivity_report(N)
    print()
